   117→  name: string
   118→  role: UserRole
   119→  company_name?: string
   120→  avatar_url?: string
   121→}
   122→
   123→export function isRecruiterRole(role: UserRole): boolean {
   124→  return ['employer', 'recruiter', 'hiring_manager', 'admin'].includes(role)
