    const total = parseInt(qb.rows[0].total);
    results.tests.push({
      level: 'L1', name: 'Question Bank',
      status: total > 0 ? 'pass' : 'fail',
      details: { total_questions: total, distinct_roles: parseInt(qb.rows[0].roles) }
